FIRRTLFolds.cpp has several unnecessary uses of RewritePattern, e.g:
```cpp
class FlattenCat : public mlir::RewritePattern {
public:
  FlattenCat(MLIRContext *context)
      : RewritePattern(CatPrimOp::getOperationName(), 0, context) {}

  LogicalResult
  matchAndRewrite(Operation *op,
                  mlir::PatternRewriter &rewriter) const override {
    auto cat = cast<CatPrimOp>(op);
    ...
}
```
We can simplify this to:
```cpp
class FlattenCat
    : public mlir::OpRewritePattern<CatPrimOp> {
public:
  using OpRewritePattern::OpRewritePattern;

  LogicalResult
  matchAndRewrite(CatPrimOp op,
                  mlir::PatternRewriter &rewriter) const override {
}
```

